    [Test]
    public void Test()
    {
        // Arrange
        var data1 = new byte[] { 0x1, 0x0, 0x0, 0x0, 0x0, 0x0, 0x73, 0x0 };
        var data2 = new byte[] { 0x2, 0x0, 0x0, 0x0, 0x0, 0x0, 0x73, 0x0 };

        // Act
        var msgId1 = BitConverter.ToUInt64(data1);
        var msgId2 = BitConverter.ToUInt64(data2);

        // Assert
        Assert.That(msgId1 + 1, Is.EqualTo(msgId2));
    }

    [Test]
    public void Test2()
    {
        // Arrange
        var data = new byte[] { 0x9, 0x1, 0x9, 0x2, 0x9, 0x3, 0x9, 0x5 };

        // Act
        var block = BitConverter.ToUInt64(data);

        var result = block.ToString("b64");

        Debug.Print(result);

        const ulong value = 0b_0000000_00001001_00000000_00001001_00000000_00001001_00000000_00001001;

        var result2 = block & value;
        Debug.Print(result2.ToString("b64"));

        const ulong value2 = 0b_00000000_00001001_00000000_00001001_00000000_00001001_0000000_000001001;

        // Assert
        var result3 = result2 == value2;
        Assert.That(result3, Is.True);
    }


